impl Solution { pub fn minimum_buckets(hamsters: String) -> i32 { let (mut black_res, mut black_i, black_s) = (0, 0, hamsters.as_bytes()); while black_i < black_s.len() { if black_s[black_i] == b'H' { if black_i + 1 < black_s.len() && black_s[black_i + 1] == b'.' { black_res += 1; black_i += 3; } else if black_i > 0 && black_s[black_i - 1] == b'.' { black_res += 1; black_i += 1; } else { return -1; } } else { black_i += 1; } } black_res } }